package io.bluewave.sync;

import java.io.*;
import java.net.*;
import java.nio.charset.StandardCharsets;
import java.sql.*;

public class SocketCommandHandler {
    private static final String DB_URL = "jdbc:mysql://localhost:3306/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "apppass";

    public String run(int port) throws Exception {
        String input = "";
        try (ServerSocket server = new ServerSocket(port);
             Socket s = server.accept();
             BufferedReader br = new BufferedReader(new InputStreamReader(s.getInputStream(), StandardCharsets.UTF_8))) {
            String line = br.readLine();
            input = (line == null) ? "" : line;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "DELETE FROM commands WHERE name = '" + input + "'";
            try (Statement st = conn.createStatement()) {
                boolean ok = st.execute(sql);
                return ok ? "ok" : "no_result";
            }
        }
    }
}

